import sys
it = iter(sys.stdin.read().split())
T = int(next(it))
def prime_factors(n):
    i = 2
    factors = {}
    while i * i <= n:
        if n % i:
            i += 1
        else:
            n //= i
            factors[i] = factors.get(i, 0) + 1
    if n > 1:
        factors[n] = factors.get(n, 0) + 1
    return factors
for _ in range(T):
    N = int(next(it))
    factors = prime_factors(N)
    output = []
    for p in sorted(factors.keys()):
        e = factors[p]
        if e == 1:
            output.append(str(p))
        else:
            output.append(f'{p}^{e}')
    print(' * '.join(output))

