#include <bits/stdc++.h>
using namespace std;
map<long long, int> prime_factors(long long n) {
    map<long long, int> factors;
    for (long long i = 2; i * i <= n; i++) {
        while (n % i == 0) {
            n /= i;
            factors[i]++;
        }
    }
    if (n > 1) factors[n]++;
    return factors;
}
int main() {
    int T;
    cin >> T;
    for (int _ = 0; _ < T; _++) {
        long long N;
        cin >> N;
        map<long long, int> factors = prime_factors(N);
        vector<string> output;
        for (auto& p : factors) {
            if (p.second == 1) {
                output.push_back(to_string(p.first));
            } else {
                output.push_back(to_string(p.first) + '^' + to_string(p.second));
            }
        }
        for (size_t i = 0; i < output.size(); i++) {
            cout << output[i];
            if (i < output.size() - 1) cout << " * ";
        }
        cout << endl;
    }
}
